# Ensure variables are cleanly initialized inside the runtime file context`n$bestiaryFolder = (Get-Item .).FullName`n$rawImageFolder = "D:\5etools-img\5etools-img\bestiary\XMM"`n`nWrite-Host "==================================================" -ForegroundColor Cyan`nWrite-Host "       STARTING XMM PLURAL SWEEP & INJECTION       " -ForegroundColor Cyan`nWrite-Host "==================================================" -ForegroundColor Cyan`n`nif (-not (Test-Path $rawImageFolder)) {`n    Write-Host "[-] Error: Source directory `$rawImageFolder` cannot be reached." -ForegroundColor Red`n    Exit`n}`n`nGet-ChildItem -Path `$bestiaryFolder -Directory | ForEach-Object {`n    `$currentCreatureFolder = `$_.FullName`n    `$imgSubFolder = Join-Path `$currentCreatureFolder "img"`n`n    Get-ChildItem -Path `$currentCreatureFolder -Filter "*.md" | ForEach-Object {`n        `$monsterName = `$_.BaseName`n        `$expectedWebp = "`$monsterName.webp"`n        `$destinationPath = Join-Path `$imgSubFolder `$expectedWebp`n        `n        if (-not (Test-Path `$destinationPath)) {`n            `$baseSlug = `$monsterName.ToLower().Replace("-xmm", "").Replace("-xphb", "").Replace("-lmop", "").Trim()`n            `$humanReadable = (Get-Culture).TextInfo.ToTitleCase(`$baseSlug.Replace("-", " "))`n            `$humanPluralS  = `$humanReadable + "s.webp"`n            `$humanPluralEs = `$humanReadable + "es.webp"`n            `n            `$sourceImagePathS  = Join-Path `$rawImageFolder `$humanPluralS`n            `$sourceImagePathEs = Join-Path `$rawImageFolder `$humanPluralEs`n            `n            if (Test-Path `$sourceImagePathS) {`n                if (-not (Test-Path `$imgSubFolder)) { New-Item -Path `$imgSubFolder -ItemType Directory | Out-Null }`n                Copy-Item -Path `$sourceImagePathS -Destination `$destinationPath -Force`n                Write-Host "   [+] Linked Plural: `$humanPluralS -> `$(`$_.Parent.Name)/img/`$expectedWebp" -ForegroundColor Green`n            } `n            elseif (Test-Path `$sourceImagePathEs) {`n                if (-not (Test-Path `$imgSubFolder)) { New-Item -Path `$imgSubFolder -ItemType Directory | Out-Null }`n                Copy-Item -Path `$sourceImagePathEs -Destination `$destinationPath -Force`n                Write-Host "   [+] Linked Plural: `$humanPluralEs -> `$(`$_.Parent.Name)/img/`$expectedWebp" -ForegroundColor Green`n            }`n        }`n    }`n}`n`nWrite-Host "`n==================================================" -ForegroundColor Cyan`nWrite-Host " Sweep complete! Fire off the link injector next." -ForegroundColor Cyan`nWrite-Host "==================================================" -ForegroundColor Cyan

